// ---------------------------------------------------------------------------
// Story 2 — AnimatedDemo (using baseline values for illustration)
// ---------------------------------------------------------------------------
export const AnimatedDemo = {
  name: 'Animated demo',
  render: () => {
    // Using generic illustrative values since Atlaskit values are not in benchmark data
    const illustrativeDurations = [
      { name: 'duration.short', value: 100 },
      { name: 'duration.medium', value: 200 },
      { name: 'duration.long', value: 400 },
    ];
    const illustrativeEasings = [
      { name: 'ease-in-out', curve: 'cubic-bezier(0.42, 0, 0.58, 1)' },
      { name: 'ease-out', curve: 'cubic-bezier(0, 0, 0.4, 1)' },
      { name: 'ease-in', curve: 'cubic-bezier(0.5, 0, 1, 1)' },
    ];

    const durationOptions = illustrativeDurations.map(d =>
      `<option value="${d.value}">${d.name} (${d.value}ms — illustrative)</option>`
    ).join('');
    const easingOptions = illustrativeEasings.map(e =>
      `<option value="${e.curve}">${e.name}</option>`
    ).join('');

    const el = document.createElement('div');
    el.innerHTML = `
      <style>
        ${baseStyles}
        .notice { background:#fff9e6;border:1px solid #f5a623;border-radius:6px;padding:12px 16px;
          font-size:12px;color:#7a4a00;margin-bottom:24px; }
        .controls { display: flex; gap: 12px; align-items: center; flex-wrap: wrap; margin-bottom: 32px; }
        select { padding: 7px 10px; border: 1px solid #e0e0e0; border-radius: 4px;
          font-family: inherit; font-size: 12px; background: #fff; min-width: 240px; }
        .play-btn { padding: 8px 20px; background: #0052cc; color: #fff; border: none;
          border-radius: 4px; font-size: 13px; font-weight: 600; cursor: pointer; font-family: inherit; }
        .play-btn:disabled { opacity: 0.5; cursor: default; }
        .stage { width: 280px; height: 80px; background: #e0ecff; border-radius: 6px;
          position: relative; margin-bottom: 16px; }
        .ref-box { width: 60px; height: 60px; background: #0052cc; border-radius: 6px;
          position: absolute; left: 0; top: 10px; }
        .labels { font-size: 11px; font-family: monospace; color: #555; line-height: 1.8; }
      </style>
      <div class="page">
        <div class="sys-badge">Atlaskit</div>
        <div class="page-title">Animated demo</div>
        <div class="notice">
          Illustrative values only — specific Atlaskit token values are not in the benchmark research data.
          These durations and curves are shown for demonstration purposes.
        </div>
        <div class="controls">
          <select id="durSel">${durationOptions}</select>
          <select id="easSel">${easingOptions}</select>
          <button class="play-btn" id="playBtn">Play</button>
        </div>
        <div class="stage"><div class="ref-box" id="box"></div></div>
        <div class="labels" id="labels"></div>
      </div>
    `;

    const durSel = el.querySelector('#durSel');
    const easSel = el.querySelector('#easSel');
    const playBtn = el.querySelector('#playBtn');
    const box = el.querySelector('#box');
    const labels = el.querySelector('#labels');

    function updateLabels() {
      labels.textContent = `duration: ${durSel.value}ms (illustrative)   easing: ${easSel.value}`;
    }
    updateLabels();
    durSel.addEventListener('change', updateLabels);
    easSel.addEventListener('change', updateLabels);

    playBtn.addEventListener('click', () => {
      if (playBtn.disabled) return;
      playBtn.disabled = true;
      const dur = parseInt(durSel.value, 10);
      box.animate(
        [{ transform: 'translateX(0px)' }, { transform: 'translateX(120px)' }, { transform: 'translateX(0px)' }],
        { duration: dur * 2, easing: easSel.value, fill: 'forwards' }
      ).onfinish = () => { playBtn.disabled = false; };
    });

    return el;
  },
};

